import heapq

class Solution:
    def shiftDistance(self, s, t, nextCost, previousCost):
        cache = {}

        def dijkstra(src):
            if src in cache:
                return cache[src]
            dist = [float('inf')] * 26
            dist[src] = 0
            pq = [(0, src)]
            while pq:
                d, u = heapq.heappop(pq)
                if d > dist[u]:
                    continue
                v = (u + 1) % 26
                nd = d + nextCost[u]
                if nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(pq, (nd, v))
                v2 = (u - 1) % 26
                nd2 = d + previousCost[u]
                if nd2 < dist[v2]:
                    dist[v2] = nd2
                    heapq.heappush(pq, (nd2, v2))
            cache[src] = dist
            return dist

        total = 0
        for a, b in zip(s, t):
            ca, cb = ord(a) - 97, ord(b) - 97
            total += dijkstra(ca)[cb]
        return total

