            if ca == cb:
                continue
            fwd = 0
            c = ca
            while c != cb:
                fwd += nextCost[c]
                c = (c + 1) % 26
            back = 0
            c = ca
            while c != cb:
                back += previousCost[c]
                c = (c - 1) % 26
            total += min(fwd, back)
        return total

