var shiftDistance = function(s, t, nextCost, previousCost) {
    let total = 0;
    for (let i = 0; i < s.length; i++) {
        const ca = s.charCodeAt(i) - 97, cb = t.charCodeAt(i) - 97;
        if (ca === cb) continue;
        let fwd = 0, c = ca;
        while (c !== cb) {
            fwd += nextCost[c];
            c = (c + 1) % 26;
        }
        let back = 0;
        c = ca;
        while (c !== cb) {
            back += previousCost[c];
            c = (c - 1 + 26) % 26;
        }
        total += Math.min(fwd, back);
    }
    return total;
};
